class Solution:
    def colorTheGrid(self, m, n):
        MOD = 10**9 + 7
        from itertools import product
        cols = []
        for combo in product(range(3), repeat=m):
            ok = True
            for i in range(m - 1):
                if combo[i] == combo[i + 1]:
                    ok = False
                    break
            if ok:
                cols.append(combo)
        def compat(a, b):
            for i in range(m):
                if a[i] == b[i]:
                    return False
            return True
        dp = {c: 1 for c in cols}
        for _ in range(n - 1):
            ndp = {c: 0 for c in cols}
            for a in cols:
                if dp[a] == 0:
                    continue
                for b in cols:
                    if compat(a, b):
                        ndp[b] = (ndp[b] + dp[a]) % MOD
            dp = ndp
        return sum(dp.values()) % MOD

