        from itertools import product
        cols = []
        for combo in product(range(3), repeat=m):
            if all(combo[i] != combo[i + 1] for i in range(m - 1)):
                cols.append(combo)
        idx = {c: i for i, c in enumerate(cols)}
        trans = [[] for _ in cols]
        for i, a in enumerate(cols):
            for j, b in enumerate(cols):
                if all(a[k] != b[k] for k in range(m)):
                    trans[i].append(j)
        dp = [1] * len(cols)
        for _ in range(n - 1):
            ndp = [0] * len(cols)
            for i in range(len(cols)):
                if dp[i]:
                    for j in trans[i]:
                        ndp[j] = (ndp[j] + dp[i]) % MOD
            dp = ndp
        return sum(dp) % MOD

