var colorTheGrid = function(m, n) {
    const MOD = 1000000007n;
    const cols = [];
    const total = Math.pow(3, m);
    for (let mask = 0; mask < total; mask++) {
        const col = [];
        let x = mask;
        for (let k = 0; k < m; k++) { col.push(x % 3); x = Math.floor(x / 3); }
        let ok = true;
        for (let i = 0; i < m - 1; i++) if (col[i] === col[i + 1]) { ok = false; break; }
        if (ok) cols.push(col);
    }
    const trans = cols.map(() => []);
    for (let i = 0; i < cols.length; i++) {
        for (let j = 0; j < cols.length; j++) {
            let ok = true;
            for (let k = 0; k < m; k++) if (cols[i][k] === cols[j][k]) { ok = false; break; }
            if (ok) trans[i].push(j);
        }
    }
    let dp = new Array(cols.length).fill(1n);
    for (let step = 0; step < n - 1; step++) {
        const ndp = new Array(cols.length).fill(0n);
        for (let i = 0; i < cols.length; i++) {
            if (dp[i] !== 0n) {
                for (const j of trans[i]) ndp[j] = (ndp[j] + dp[i]) % MOD;
            }
        }
        dp = ndp;
    }
    let s = 0n;
    for (const v of dp) s = (s + v) % MOD;
    return Number(s);
};
